   321→### TUTTI I PASSAGGI DEL PROBLEMA
   322→${currentHomework.steps.map((s, i) => `${i + 1}. ${s.description} ${s.completed ? '✓' : '○'}`).join('\n')}
   323→
   324→**IMPORTANTE**: Concentrati SOLO sul passaggio attuale. Non anticipare i successivi.`;
   325→    }
   326→
   327→    return fullPrompt;
   328→  }, [connectedMaestro, currentHomework]);
   329→
   330→  // Send message to maieutic API
   331→  const sendMaieuticMessage = useCallback(async (message: string) => {
   332→    setIsLoadingChat(true);
   333→
   334→    try {
   335→      const response = await fetch('/api/chat', {
   336→        method: 'POST',
   337→        headers: { 'Content-Type': 'application/json' },
   338→        body: JSON.stringify({
   339→          messages: [
   340→            ...maieuticChat.map(m => ({ role: m.role, content: m.content })),
   341→            { role: 'user', content: message },
   342→          ],
   343→          systemPrompt: getMaieuticSystemPrompt(),
   344→          maestroId: connectedMaestro?.id || 'maieutic',
   345→          enableTools: false, // No tools for maieutic chat
   346→        }),
   347→      });
   348→
   349→      if (!response.ok) {
   350→        const errorData = await response.json().catch(() => ({}));
   351→        throw new Error(errorData.message || 'Failed to get response');
   352→      }
   353→
   354→      const data = await response.json();
   355→
   356→      setMaieuticChat(prev => [...prev, {
   357→        role: 'assistant',
   358→        content: data.content || 'Mi dispiace, non ho capito. Puoi riformulare la domanda?',
   359→        timestamp: new Date(),
   360→      }]);
   361→    } catch (err) {
   362→      logger.error('Maieutic chat error', { error: String(err) });
   363→      setMaieuticChat(prev => [...prev, {
   364→        role: 'assistant',
   365→        content: 'Scusa, c\'è stato un problema. Prova a riformulare la domanda.',
   366→        timestamp: new Date(),
   367→      }]);
   368→    } finally {
   369→      setIsLoadingChat(false);
   370→    }
   371→  }, [maieuticChat, getMaieuticSystemPrompt, connectedMaestro]);
   372→
   373→  // Handle chat submit
   374→  const handleChatSubmit = useCallback(() => {
   375→    if (!chatInput.trim() || isLoadingChat) return;
   376→
   377→    setMaieuticChat(prev => [...prev, {
   378→      role: 'user',
   379→      content: chatInput,
   380→      timestamp: new Date(),
   381→    }]);
   382→    sendMaieuticMessage(chatInput);
   383→    setChatInput('');
   384→  }, [chatInput, isLoadingChat, sendMaieuticMessage]);
   385→
   386→  // Load homework from history
   387→  const loadHomework = useCallback((homework: Homework) => {
   388→    setCurrentHomework(homework);
   389→    setMaieuticChat([]);
   390→    setShowHistory(false);
   391→  }, []);
   392→
   393→  // Delete homework from history
   394→  const deleteHomework = useCallback(async (id: string) => {
   395→    await deleteSession(id);
   396→    if (currentHomework?.id === id) {
   397→      setCurrentHomework(null);
   398→    }
   399→  }, [currentHomework, deleteSession]);
   400→
   401→  // Start new homework
   402→  const startNew = useCallback(() => {
   403→    setCurrentHomework(null);
   404→    setMaieuticChat([]);
   405→  }, []);
   406→
   407→  return (
   408→    <div className="space-y-6">
   409→      {/* Header */}
   410→      <div className="flex items-center justify-between">
   411→        <div>
   412→          <h1 className="text-3xl font-bold text-slate-900 dark:text-white">
   413→            Materiali di Studio
   414→          </h1>
   415→          <p className="text-slate-600 dark:text-slate-400 mt-1">
   416→            Metodo maieutico: ti guido a trovare la soluzione da solo
   417→          </p>
   418→          {/* Connected Maestro badge */}
   419→          {connectedMaestro && (
   420→            <div className="mt-2 inline-flex items-center gap-2 px-3 py-1.5 rounded-full bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800">
   421→              <div
   422→                className="w-6 h-6 rounded-full flex items-center justify-center text-white text-xs font-bold"
   423→                style={{ backgroundColor: connectedMaestro.color }}
   424→              >
   425→                {connectedMaestro.avatar}
   426→              </div>
   427→              <span className="text-sm font-medium text-blue-700 dark:text-blue-300">
   428→                Con {connectedMaestro.name}
   429→              </span>
   430→              <GraduationCap className="w-4 h-4 text-blue-500" />
   431→            </div>
   432→          )}
   433→        </div>
   434→        <div className="flex gap-2">
   435→          {currentHomework && (
   436→            <Button variant="outline" onClick={startNew}>
   437→              Nuovo problema
   438→            </Button>
   439→          )}
   440→          <Button
   441→            variant="outline"
   442→            onClick={() => setShowHistory(!showHistory)}
   443→            className={cn(showHistory && 'bg-slate-100 dark:bg-slate-800')}
   444→          >
   445→            <History className="w-4 h-4 mr-2" />
   446→            Cronologia ({displayHistory.length})
   447→          </Button>
   448→        </div>
   449→      </div>
   450→
   451→      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
   452→        {/* Main content */}
   453→        <div className={cn('lg:col-span-2', showHistory && 'lg:col-span-2')}>
   454→          {/* Subject Confirmation - shown inline after photo capture */}
   455→          {showSubjectDialog ? (
   456→            <SubjectConfirmationDialog
   457→              key={pendingHomework?.id || detectedSubject}
   458→              detectedSubject={detectedSubject}
   459→              isOpen={showSubjectDialog}
