   477→        {/* Sidebar: History or Chat */}
   478→        <div className="space-y-4">
   479→          {/* History panel */}
   480→          <AnimatePresence>
   481→            {showHistory && (
   482→              <motion.div
   483→                initial={{ opacity: 0, x: 20 }}
   484→                animate={{ opacity: 1, x: 0 }}
   485→                exit={{ opacity: 0, x: 20 }}
   486→              >
