   502→                    {historyLoading ? (
   503→                      <div className="flex items-center justify-center py-8">
   504→                        <Loader2 className="w-6 h-6 animate-spin text-blue-500" />
   505→                      </div>
   506→                    ) : displayHistory.length === 0 ? (
