   529→                                {new Date(hw.createdAt).toLocaleDateString('it-IT')}
   530→                              </p>
   531→                            </div>
   532→                            <div className="flex items-center gap-1">
   533→                              {hw.completedAt && (
   534→                                <CheckCircle className="w-4 h-4 text-green-500" />
   535→                              )}
   536→                              <Button
   537→                                variant="ghost"
   538→                                size="icon-sm"
   539→                                className="opacity-0 group-hover:opacity-100"
   540→                                onClick={(e) => {
   541→                                  e.stopPropagation();
   542→                                  deleteHomework(hw.id);
   543→                                }}
   544→                                aria-label="Elimina problema"
   545→                              >
   546→                                <Trash2 className="w-3 h-3 text-red-500" />
   547→                              </Button>
   548→                            </div>
   549→                          </div>
   550→                        </div>
   551→                      ))
   552→                    )}
   553→                  </CardContent>
   554→                </Card>
   555→              </motion.div>
   556→            )}
   557→          </AnimatePresence>
   558→
   559→          {/* Maieutic chat */}
   560→          {currentHomework && (
   561→            <Card>
   562→              <CardHeader className="pb-3">
   563→                <CardTitle className="text-lg flex items-center gap-2">
   564→                  <MessageCircle className="w-5 h-5 text-blue-500" />
   565→                  Dialogo Maieutico
   566→                </CardTitle>
   567→              </CardHeader>
   568→              <CardContent>
   569→                <div className="space-y-3 max-h-80 overflow-y-auto mb-4">
   570→                  {maieuticChat.length === 0 ? (
   571→                    <div className="text-center py-6">
