   609→                    onChange={(e) => setChatInput(e.target.value)}
   610→                    onKeyDown={(e) => e.key === 'Enter' && handleChatSubmit()}
   611→                    placeholder="Fai una domanda..."
   612→                    className="flex-1 px-3 py-2 text-sm rounded-lg bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
   613→                    disabled={isLoadingChat}
   614→                  />
   615→                  <Button
   616→                    size="sm"
