   631→}
   632→
   633→// Utility: Convert file to base64
   634→function fileToBase64(file: File): Promise<string> {
   635→  return new Promise((resolve, reject) => {
   636→    const reader = new FileReader();
   637→    reader.onload = () => resolve(reader.result as string);
   638→    reader.onerror = reject;
